import logging
from flask import Flask, request

app = Flask(__name__)

# Configure logging
log_file_path = '/path/to/your/logfile.log'
logging.basicConfig(filename=log_file_path, level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

@app.route('/log', methods=['POST'])
def log_message():
    try:
        data = request.json
        message = data.get('message')
        if not message:
            return 'No message provided', 400
        
        # Prevent log injection by escaping special characters
        safe_message = message.replace('\n', '\\n').replace('\r', '\\r').replace('\t', '\\t')
        
        logging.info(safe_message)
        return 'Log message received and logged successfully', 200
    
    except Exception as e:
        logging.error(f'Error processing log request: {e}')
        return f'An error occurred: {str(e)}', 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)